16	      expect(quote({ items: [{ type: "staff" }] })).toBe(85);
17	    });
18	    it("returns 45 G for a single plain potion (40 base + 5 fee)", () => {
19	      expect(quote({ items: [{ type: "potion" }] })).toBe(45);
20	    });
21	    it.todo("returns 30 G for a single rune (25 base + 5 fee)");
22	    it.todo("returns 30 G for a single moonstone (25 base + 5 fee)");
23	  });
24	
25	  describe("quote — component building blocks", () => {
26	    it.todo("returns 55 G for 2 runes (50 base + 5 fee)");
27	    it.todo("returns 65 G for 3 runes (60 base block + 5 fee)");
28	    it.todo("returns 105 G for 4 runes (100 base, no block + 5 fee)");
29	    it.todo("returns 180 G for 7 runes (175 base + 5 fee)");
30	    it.todo("returns 80 G for 2 runes + 1 moonstone (75 base, no block: different types + 5 fee)");
31	    it.todo("returns 125 G for 3 runes + 3 moonstones (120 base, two separate blocks + 5 fee)");
32	  });
33	
34	  describe("quote — item-specific modifiers", () => {
35	    it.todo("adds 50% curse surcharge to a cursed sword's base premium");
36	    it.todo("adds 30% high-enchantment surcharge to a sword with enchantment exactly 5");
37	    it.todo("does not add high-enchantment surcharge to a sword with enchantment 4");
38	    it.todo("applies both curse and high-enchantment surcharges to a cursed sword with enchantment 5");
39	  });
40	
41	  describe("quote — policy-wide modifiers", () => {
42	    it.todo("applies 20% loyalty discount for a customer with exactly 2 years with MHPCO");
43	    it.todo("does not apply loyalty discount for a customer with fewer than 2 years");
