47	
48	  describe("quote — modifier scope on multi-item policies", () => {
49	    it.todo("sums item base premiums into the policy base premium for a cursed sword and a plain amulet");
50	    it.todo("applies the curse surcharge to only the cursed item's base premium, not the policy total");
