52	
53	  describe("quote — rounding", () => {
54	    it.todo("rounds the final premium up to whole G (197.5 → 198)");
55	  });
56	
57	  describe("quote — integration examples", () => {
58	    it.todo("returns 165 G for a newcomer's cursed steel sword at enchantment 3");
59	    it.todo("returns 160 G for a long-standing customer's second-quote cursed steel sword at enchantment 7");
