61	
62	  describe("claim — standard reimbursement and deductible", () => {
63	    it.todo("pays 400 G for a steel sword enchantment 3 with 500 G damage (full minus 100 deductible)");
64	    it.todo("pays 100 G for a rune with 200 G damage (full minus 100 deductible)");
