1	export interface QuoteInput {
2	  items: { type: string }[];
3	}
4	
5	const PROCESSING_FEE = 5;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	export function quote(input: QuoteInput): number {
15	  const basePremiumTotal = input.items.reduce(
16	    (sum, item) => sum + BASE_PREMIUMS[item.type],
17	    0,
18	  );
19	  return basePremiumTotal + PROCESSING_FEE;
20	}
21	
22	export function claim(): number {
23	  return undefined as unknown as number;
24	}
